import { render, screen } from '@testing-library/svelte';
import { describe, it, expect } from 'vitest';
import LoadingSpinner from './LoadingSpinner.svelte';

describe('LoadingSpinner', () => {
  it('renders with default props', () => {
    render(LoadingSpinner);

    const spinner = screen.getByRole('status', { name: 'Loading' });
    expect(spinner).toBeInTheDocument();

    const svg = spinner.querySelector('svg');
    expect(svg).toHaveAttribute('width', '24');
    expect(svg).toHaveAttribute('height', '24');
  });

  it('renders with small size', () => {
    render(LoadingSpinner, { props: { size: 'sm' } });

    const spinner = screen.getByRole('status');
    const svg = spinner.querySelector('svg');
    expect(svg).toHaveAttribute('width', '16');
    expect(svg).toHaveAttribute('height', '16');
  });

  it('renders with medium size', () => {
    render(LoadingSpinner, { props: { size: 'md' } });

    const spinner = screen.getByRole('status');
    const svg = spinner.querySelector('svg');
    expect(svg).toHaveAttribute('width', '24');
    expect(svg).toHaveAttribute('height', '24');
  });

  it('renders with large size', () => {
    render(LoadingSpinner, { props: { size: 'lg' } });

    const spinner = screen.getByRole('status');
    const svg = spinner.querySelector('svg');
    expect(svg).toHaveAttribute('width', '32');
    expect(svg).toHaveAttribute('height', '32');
  });

  it('applies custom color', () => {
    const { container } = render(LoadingSpinner, { props: { color: 'secondary' } });

    const spinner = container.querySelector('.loading-spinner');
    expect(spinner).toHaveStyle('--color: var(--secondary)');
  });

  it('has screen reader text', () => {
    render(LoadingSpinner);

    const srText = screen.getByText('Loading...');
    expect(srText).toBeInTheDocument();
    expect(srText).toHaveClass('sr-only');
  });

  it('has proper ARIA attributes', () => {
    render(LoadingSpinner);

    const svg = screen.getByRole('status', { name: 'Loading' });
    expect(svg).toHaveAttribute('aria-label', 'Loading');
  });
});

