import { render, screen } from '@testing-library/svelte';
import { describe, it, expect } from 'vitest';
import Skeleton from './Skeleton.svelte';

describe('Skeleton', () => {
  it('renders with default props', () => {
    const { container } = render(Skeleton);

    const skeleton = screen.getByRole('status', { name: 'Loading content' });
    expect(skeleton).toBeInTheDocument();
    expect(skeleton).toHaveClass('skeleton', 'animate');

    const computedStyle = window.getComputedStyle(skeleton);
    expect(computedStyle.width).toBe('100%');
    expect(computedStyle.height).toBe('1rem');
    expect(computedStyle.borderRadius).toBe('0.25rem');
  });

  it('applies custom dimensions', () => {
    const { container } = render(Skeleton, { 
      props: { 
        width: '200px', 
        height: '50px' 
      } 
    });

    const skeleton = container.querySelector('.skeleton');
    expect(skeleton).toHaveStyle({
      width: '200px',
      height: '50px'
    });
  });

  it('applies custom border radius', () => {
    const { container } = render(Skeleton, { 
      props: { 
        borderRadius: '10px' 
      } 
    });

    const skeleton = container.querySelector('.skeleton');
    expect(skeleton).toHaveStyle({
      borderRadius: '10px'
    });
  });

  it('can disable animation', () => {
    const { container } = render(Skeleton, { 
      props: { 
        animate: false 
      } 
    });

    const skeleton = container.querySelector('.skeleton');
    expect(skeleton).toHaveClass('skeleton');
    expect(skeleton).not.toHaveClass('animate');
  });

  it('has screen reader text', () => {
    render(Skeleton);

    const srText = screen.getByText('Loading...');
    expect(srText).toBeInTheDocument();
    expect(srText).toHaveClass('sr-only');
  });

  it('has proper ARIA attributes', () => {
    render(Skeleton);

    const skeleton = screen.getByRole('status');
    expect(skeleton).toHaveAttribute('aria-label', 'Loading content');
  });
});

