     8→  export let size: 'sm' | 'md' | 'lg' | 'xl' = 'md';
     9→  export let closeOnEscape = true;
    10→  export let closeOnClickOutside = true;
    11→  export let showCloseButton = true;
    12→  
    13→  const dispatch = createEventDispatcher();
    14→  
    15→  let modal: HTMLDivElement;
    16→  let previousFocus: HTMLElement | null = null;
    17→  
