import { render, screen, fireEvent, waitFor } from '@testing-library/svelte';
import { describe, it, expect, vi } from 'vitest';
import Modal from './Modal.svelte';
import { tick } from 'svelte';

describe('Modal', () => {
  it('does not render when closed', () => {
    render(Modal, { props: { open: false } });

    expect(screen.queryByRole('dialog')).not.toBeInTheDocument();
  });

  it('renders when open', () => {
    render(Modal, { props: { open: true, title: 'Test Modal' } });

    const dialog = screen.getByRole('dialog');
    expect(dialog).toBeInTheDocument();
    expect(dialog).toHaveAttribute('aria-modal', 'true');

    const title = screen.getByText('Test Modal');
    expect(title).toBeInTheDocument();
  });

  it('renders with different sizes', () => {
    const { rerender } = render(Modal, { props: { open: true, size: 'sm' } });
    expect(screen.getByRole('dialog')).toHaveClass('max-w-md');

    rerender({ props: { open: true, size: 'md' } });
    expect(screen.getByRole('dialog')).toHaveClass('max-w-lg');

    rerender({ props: { open: true, size: 'lg' } });
    expect(screen.getByRole('dialog')).toHaveClass('max-w-2xl');

    rerender({ props: { open: true, size: 'xl' } });
    expect(screen.getByRole('dialog')).toHaveClass('max-w-4xl');
  });

  it('closes on escape key when enabled', async () => {
    const { component } = render(Modal, { 
      props: { 
        open: true, 
        closeOnEscape: true 
      } 
    });

    const closeSpy = vi.fn();
    component.$on('close', closeSpy);

    const backdrop = screen.getByRole('presentation');
