import { render, screen, fireEvent, waitFor } from '@testing-library/svelte';
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import Toast from './Toast.svelte';

describe('Toast', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it('renders with message', () => {
    render(Toast, { props: { message: 'Test notification' } });

    const alert = screen.getByRole('alert');
    expect(alert).toBeInTheDocument();
    expect(screen.getByText('Test notification')).toBeInTheDocument();
  });

  it('renders with different types', () => {
    const { rerender } = render(Toast, { 
      props: { 
        type: 'success', 
        message: 'Success' 
      } 
    });
    expect(screen.getByRole('alert')).toHaveClass('toast-success');

    rerender({ props: { type: 'error', message: 'Error' } });
    expect(screen.getByRole('alert')).toHaveClass('toast-error');

    rerender({ props: { type: 'warning', message: 'Warning' } });
    expect(screen.getByRole('alert')).toHaveClass('toast-warning');

    rerender({ props: { type: 'info', message: 'Info' } });
    expect(screen.getByRole('alert')).toHaveClass('toast-info');
  });

  it('shows appropriate icon for each type', () => {
    const { container, rerender } = render(Toast, { 
      props: { type: 'success', message: 'Test' } 
    });

    // Each type should have its specific icon
    const iconWrapper = container.querySelector('.toast-icon');
    expect(iconWrapper).toBeInTheDocument();

    // Test that color is applied
    expect(iconWrapper).toHaveStyle('color: var(--success)');

    rerender({ props: { type: 'error', message: 'Test' } });
    expect(container.querySelector('.toast-icon')).toHaveStyle('color: var(--error)');
  });

  it('auto-closes after duration', async () => {
    const onCloseSpy = vi.fn();
    render(Toast, { 
      props: { 
        message: 'Test',
        duration: 1000,
        onClose: onCloseSpy
      } 
    });

    expect(screen.getByRole('alert')).toBeInTheDocument();

    // Fast-forward time
    vi.advanceTimersByTime(1000);

    await waitFor(() => {
      expect(onCloseSpy).toHaveBeenCalled();
    });
  });

  it('does not auto-close when duration is 0', () => {
    const onCloseSpy = vi.fn();
    render(Toast, { 
      props: { 
        message: 'Test',
        duration: 0,
        onClose: onCloseSpy
      } 
    });

    vi.advanceTimersByTime(10000);
    expect(onCloseSpy).not.toHaveBeenCalled();
  });

  it('shows close button when closable', () => {
    render(Toast, { 
      props: { 
        message: 'Test',
        closable: true
      } 
    });

    const closeButton = screen.getByLabelText('Close notification');
    expect(closeButton).toBeInTheDocument();
  });

  it('hides close button when not closable', () => {
    render(Toast, { 
      props: { 
        message: 'Test',
        closable: false
      } 
    });

    expect(screen.queryByLabelText('Close notification')).not.toBeInTheDocument();
  });

  it('closes when close button is clicked', async () => {
    const onCloseSpy = vi.fn();
    render(Toast, { 
      props: { 
        message: 'Test',
        closable: true,
        duration: 0, // Disable auto-close
        onClose: onCloseSpy
      } 
    });

    const closeButton = screen.getByLabelText('Close notification');
    fireEvent.click(closeButton);

    await waitFor(() => {
      expect(onCloseSpy).toHaveBeenCalled();
    });
  });

  it('has proper ARIA role', () => {
    render(Toast, { props: { message: 'Test' } });

    const alert = screen.getByRole('alert');
    expect(alert).toBeInTheDocument();
  });
});

