import { render, screen, fireEvent, waitFor } from '@testing-library/svelte';
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import ErrorBoundary from './ErrorBoundary.svelte';

describe('ErrorBoundary', () => {
  let originalLocation: Location;

  beforeEach(() => {
    originalLocation = window.location;
    // Mock window.location.reload
    delete (window as any).location;
    window.location = { ...originalLocation, reload: vi.fn() };
  });

  afterEach(() => {
    window.location = originalLocation;
  });

  it('renders slot content when no error', () => {
    render(ErrorBoundary, {
      slots: {
        default: '<p>Normal content</p>'
      }
    });

    expect(screen.getByText('Normal content')).toBeInTheDocument();
    expect(screen.queryByText('Something went wrong')).not.toBeInTheDocument();
  });

  it('shows error fallback when error occurs', async () => {
    const onErrorSpy = vi.fn();
    const { component } = render(ErrorBoundary, {
      props: {
        fallback: true,
        onError: onErrorSpy
      },
      slots: {
        default: '<p>Normal content</p>'
      }
    });

    // Simulate an error
    const error = new Error('Test error');
    const errorEvent = new ErrorEvent('error', { error });
    window.dispatchEvent(errorEvent);

    await waitFor(() => {
      expect(screen.getByText('Something went wrong')).toBeInTheDocument();
      expect(screen.getByText('An unexpected error occurred. Please try refreshing the page.')).toBeInTheDocument();
      expect(onErrorSpy).toHaveBeenCalledWith(error);
    });
  });

  it('does not show fallback when fallback prop is false', async () => {
    const onErrorSpy = vi.fn();
    render(ErrorBoundary, {
      props: {
        fallback: false,
        onError: onErrorSpy
      },
      slots: {
        default: '<p>Normal content</p>'
      }
    });

    // Simulate an error
    const error = new Error('Test error');
    const errorEvent = new ErrorEvent('error', { error });
    window.dispatchEvent(errorEvent);

    await waitFor(() => {
      expect(onErrorSpy).toHaveBeenCalledWith(error);
      expect(screen.getByText('Normal content')).toBeInTheDocument();
      expect(screen.queryByText('Something went wrong')).not.toBeInTheDocument();
    });
  });

  it('displays error details', async () => {
    render(ErrorBoundary, {
      props: {
        fallback: true
      }
    });

    // Simulate an error with stack trace
    const error = new Error('Test error message');
    error.stack = 'Error: Test error message\n    at someFunction (file.js:10:5)';
    const errorEvent = new ErrorEvent('error', { error });
    window.dispatchEvent(errorEvent);

    await waitFor(() => {
      const details = screen.getByText('Error details');
      expect(details).toBeInTheDocument();

      // Click to expand details
      fireEvent.click(details);

      expect(screen.getByText(error.stack)).toBeInTheDocument();
    });
  });

  it('reloads page when refresh button is clicked', async () => {
    render(ErrorBoundary, {
      props: {
        fallback: true
      }
    });

    // Simulate an error
    const error = new Error('Test error');
    const errorEvent = new ErrorEvent('error', { error });
    window.dispatchEvent(errorEvent);

    await waitFor(() => {
      const refreshButton = screen.getByText('Refresh page');
      expect(refreshButton).toBeInTheDocument();

      fireEvent.click(refreshButton);

      expect(window.location.reload).toHaveBeenCalled();
    });
  });

  it('prevents default error handling', async () => {
    render(ErrorBoundary, {
      props: {
        fallback: true
      }
    });

    // Create error event with preventDefault spy
    const error = new Error('Test error');
    const errorEvent = new ErrorEvent('error', { error });
    const preventDefaultSpy = vi.spyOn(errorEvent, 'preventDefault');

    window.dispatchEvent(errorEvent);

    await waitFor(() => {
      expect(preventDefaultSpy).toHaveBeenCalled();
    });
  });

  it('cleans up error handler on unmount', () => {
    const removeEventListenerSpy = vi.spyOn(window, 'removeEventListener');

    const { unmount } = render(ErrorBoundary, {
      slots: {
        default: '<p>Normal content</p>'
      }
    });

    unmount();

    expect(removeEventListenerSpy).toHaveBeenCalledWith('error', expect.any(Function));
  });
});

