import { render, screen, fireEvent } from '@testing-library/svelte';
import { describe, it, expect, vi } from 'vitest';
import Header from './Header.svelte';
import { toggleDarkMode, settings } from '$lib/stores/app';
import { get } from 'svelte/store';

// Mock the store module
vi.mock('$lib/stores/app', () => ({
  settings: {
    subscribe: vi.fn((fn) => {
      fn({ theme: 'light', fontSize: 'medium' });
      return () => {};
    })
  },
  toggleDarkMode: vi.fn()
}));

describe('Header', () => {
  it('renders logo and navigation links', () => {
    render(Header);

    // Logo
    const logo = screen.getByText('PsyForge');
    expect(logo).toBeInTheDocument();
    expect(logo.closest('a')).toHaveAttribute('href', '/');

    // Navigation links
    expect(screen.getByText('Experiments')).toBeInTheDocument();
    expect(screen.getByText('Timeline')).toBeInTheDocument();
    expect(screen.getByText('Editor')).toBeInTheDocument();
    expect(screen.getByText('Docs')).toBeInTheDocument();
  });

  it('toggles sidebar when menu button is clicked', () => {
    let sidebarOpen = true;
    const { component } = render(Header, { props: { sidebarOpen } });

    const menuButton = screen.getByLabelText('Toggle sidebar');
    expect(menuButton).toHaveAttribute('title', 'Hide sidebar');

    fireEvent.click(menuButton);

    component.$on('click', (e) => {
      sidebarOpen = !sidebarOpen;
    });
  });

  it('has accessible navigation', () => {
    render(Header);

    const nav = screen.getByRole('navigation', { name: 'Main navigation' });
    expect(nav).toBeInTheDocument();

    const links = nav.querySelectorAll('a');
    expect(links).toHaveLength(4);
  });

  it('renders theme toggle button', () => {
    render(Header);

    const themeToggle = screen.getByLabelText('Toggle dark mode');
    expect(themeToggle).toBeInTheDocument();
  });

  it('calls toggleDarkMode when theme button is clicked', () => {
    render(Header);

    const themeToggle = screen.getByLabelText('Toggle dark mode');
    fireEvent.click(themeToggle);

    expect(toggleDarkMode).toHaveBeenCalled();
  });

  it('shows sun icon in dark mode', () => {
    // Update mock to return dark theme
    vi.mocked(settings.subscribe).mockImplementation((fn) => {
      fn({ theme: 'dark', fontSize: 'medium' });
      return () => {};
    });

    const { container } = render(Header);

    // In dark mode, we show the Sun icon to switch to light mode
    const themeButton = screen.getByLabelText('Toggle dark mode');
    expect(themeButton.querySelector('svg')).toBeInTheDocument();
  });

  it('shows moon icon in light mode', () => {
    // Update mock to return light theme
    vi.mocked(settings.subscribe).mockImplementation((fn) => {
      fn({ theme: 'light', fontSize: 'medium' });
      return () => {};
    });

    const { container } = render(Header);

    // In light mode, we show the Moon icon to switch to dark mode
    const themeButton = screen.getByLabelText('Toggle dark mode');
    expect(themeButton.querySelector('svg')).toBeInTheDocument();
  });

  it('renders utility buttons', () => {
    render(Header);

    expect(screen.getByLabelText('Settings')).toBeInTheDocument();
    expect(screen.getByLabelText('Help')).toBeInTheDocument();
  });

  it('has proper ARIA labels for all buttons', () => {
    render(Header);

    expect(screen.getByLabelText('Toggle sidebar')).toBeInTheDocument();
    expect(screen.getByLabelText('Toggle dark mode')).toBeInTheDocument();
    expect(screen.getByLabelText('Settings')).toBeInTheDocument();
    expect(screen.getByLabelText('Help')).toBeInTheDocument();
  });
});

