import { render, screen, fireEvent } from '@testing-library/svelte';
import { describe, it, expect, vi } from 'vitest';
import Sidebar from './Sidebar.svelte';
import { page } from '$app/stores';
import { writable } from 'svelte/store';

// Mock the $app/stores module
vi.mock('$app/stores', () => ({
  page: writable({
    url: {
      pathname: '/'
    }
  })
}));

describe('Sidebar', () => {
  it('renders navigation items', () => {
    render(Sidebar);

    // Main navigation items
    expect(screen.getByText('Dashboard')).toBeInTheDocument();
    expect(screen.getByText('Experiments')).toBeInTheDocument();
    expect(screen.getByText('Timeline')).toBeInTheDocument();
    expect(screen.getByText('Editor')).toBeInTheDocument();
    expect(screen.getByText('Library')).toBeInTheDocument();
    expect(screen.getByText('Data')).toBeInTheDocument();
    expect(screen.getByText('Collaborate')).toBeInTheDocument();
    expect(screen.getByText('Share')).toBeInTheDocument();

    // Bottom items
    expect(screen.getByText('Documentation')).toBeInTheDocument();
    expect(screen.getByText('Settings')).toBeInTheDocument();
  });

  it('has proper navigation structure', () => {
    render(Sidebar);

    const nav = screen.getByRole('navigation', { name: 'Main navigation' });
    expect(nav).toBeInTheDocument();

    const lists = nav.querySelectorAll('.nav-list');
    expect(lists).toHaveLength(2); // Main nav and bottom nav
  });

  it('marks current page as active', () => {
    // Update the mock store
    page.set({
      url: {
        pathname: '/experiments'
      }
    });

    render(Sidebar);

    const experimentsLink = screen.getByText('Experiments').closest('a');
    expect(experimentsLink).toHaveClass('active');
    expect(experimentsLink).toHaveAttribute('aria-current', 'page');

    const dashboardLink = screen.getByText('Dashboard').closest('a');
    expect(dashboardLink).not.toHaveClass('active');
    expect(dashboardLink).not.toHaveAttribute('aria-current');
  });

  it('marks parent routes as active for sub-routes', () => {
    // Update the mock store to a sub-route
    page.set({
      url: {
        pathname: '/experiments/new'
      }
    });

    render(Sidebar);

    const experimentsLink = screen.getByText('Experiments').closest('a');
    expect(experimentsLink).toHaveClass('active');
  });

  it('renders quick action buttons', () => {
    render(Sidebar);

    const sectionTitle = screen.getByText('Quick Actions');
    expect(sectionTitle).toBeInTheDocument();

    const importButton = screen.getByText('Import Experiment');
    expect(importButton).toBeInTheDocument();
    expect(importButton.closest('button')).toHaveClass('action-button');

    const newButton = screen.getByText('New Experiment');
    expect(newButton).toBeInTheDocument();
    expect(newButton.closest('button')).toHaveClass('action-button', 'primary');
  });

  it('has correct href attributes', () => {
    render(Sidebar);

    const links = [
      { text: 'Dashboard', href: '/' },
      { text: 'Experiments', href: '/experiments' },
      { text: 'Timeline', href: '/timeline' },
      { text: 'Editor', href: '/editor' },
      { text: 'Library', href: '/library' },
      { text: 'Data', href: '/data' },
      { text: 'Collaborate', href: '/collaborate' },
      { text: 'Share', href: '/share' },
      { text: 'Documentation', href: '/docs' },
      { text: 'Settings', href: '/settings' }
    ];

    links.forEach(({ text, href }) => {
      const link = screen.getByText(text).closest('a');
      expect(link).toHaveAttribute('href', href);
    });
  });

  it('renders icons for navigation items', () => {
    const { container } = render(Sidebar);

    // Check that icons are rendered (they're SVG components)
    const navItems = container.querySelectorAll('.nav-item');
    navItems.forEach(item => {
      const svg = item.querySelector('svg');
      expect(svg).toBeInTheDocument();
    });
  });

  it('handles special case for home route', () => {
    // Set current path to home
    page.set({
      url: {
        pathname: '/'
      }
    });

    render(Sidebar);

    const dashboardLink = screen.getByText('Dashboard').closest('a');
    expect(dashboardLink).toHaveClass('active');

    // Make sure other routes starting with / are not marked active
    const experimentsLink = screen.getByText('Experiments').closest('a');
    expect(experimentsLink).not.toHaveClass('active');
  });
});

