/**
 * Core types for PsyForge GUI
 */

import type { Experiment } from '@psyforge/forgescript';

export interface Project {
	id: string;
	name: string;
	description?: string;
	experiments: ExperimentReference[];
	createdAt: Date;
	updatedAt: Date;
	collaborators: Collaborator[];
	version: string;
}

export interface ExperimentReference {
	id: string;
	name: string;
	version: string;
	lastModified: Date;
}

export interface Collaborator {
	id: string;
	name: string;
	email: string;
	role: 'owner' | 'editor' | 'viewer';
	avatar?: string;
}

export interface TimelineEvent {
	id: string;
	type: 'stimulus' | 'response' | 'wait' | 'custom';
	startTime: number;
	duration: number;
	label: string;
	data?: any;
}

export interface EditorState {
	content: string;
	language: string;
	theme: 'light' | 'dark' | 'high-contrast';
	readOnly: boolean;
	cursors?: CollaboratorCursor[];
}

export interface CollaboratorCursor {
	userId: string;
	userName: string;
	color: string;
	position: {
		line: number;
		column: number;
	};
}

export interface AppSettings {
	theme: 'light' | 'dark' | 'high-contrast';
	autoSave: boolean;
	autoSaveInterval: number;
	showPerformanceOverlay: boolean;
	accessibility: {
		reduceMotion: boolean;
		highContrast: boolean;
		fontSize: 'small' | 'medium' | 'large';
	};
}

export interface ValidationResult {
	valid: boolean;
	errors: ValidationError[];
	warnings: ValidationWarning[];
}

export interface ValidationError {
	code: string;
	message: string;
	line?: number;
	column?: number;
}

export interface ValidationWarning {
	code: string;
	message: string;
	line?: number;
	column?: number;
}

