import { render, screen, fireEvent, waitFor } from '@testing-library/svelte';
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import TimelineCanvas from './TimelineCanvas.svelte';
import type { CompiledExperiment } from '$lib/types/experiment';

// Mock the TimelineRenderer
vi.mock('./TimelineRenderer', () => ({
  createTimelineRenderer: vi.fn(() => ({
    setDimensions: vi.fn(),
    setExperiment: vi.fn(),
    setSelectedElement: vi.fn(),
    setZoom: vi.fn(),
    setPan: vi.fn(),
    render: vi.fn(),
    hitTest: vi.fn()
  }))
}));

// Mock ResizeObserver
class MockResizeObserver {
  observe = vi.fn();
  unobserve = vi.fn();
  disconnect = vi.fn();
}

global.ResizeObserver = MockResizeObserver as any;

describe('TimelineCanvas', () => {
  const mockExperiment: CompiledExperiment = {
    id: 'exp-1',
    name: 'Test Experiment',
    duration: 10000,
    timelines: [{
      id: 'timeline-1',
      name: 'Main Timeline',
      duration: 10000,
      trials: [{
        id: 'trial-1',
        name: 'Trial 1',
        duration: 5000,
        stimuli: [{
          id: 'stim-1',
          name: 'Stimulus 1',
          duration: 2000
        }]
      }]
    }]
  };

  beforeEach(() => {
    // Mock canvas context
    HTMLCanvasElement.prototype.getContext = vi.fn(() => ({
      clearRect: vi.fn(),
      fillRect: vi.fn(),
      strokeRect: vi.fn(),
      fillText: vi.fn(),
      save: vi.fn(),
      restore: vi.fn(),
      scale: vi.fn(),
      translate: vi.fn(),
      beginPath: vi.fn(),
      moveTo: vi.fn(),
      lineTo: vi.fn(),
      stroke: vi.fn(),
      rect: vi.fn(),
      clip: vi.fn(),
      setLineDash: vi.fn()
    }));
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('renders canvas element', () => {
    render(TimelineCanvas);

    const canvas = screen.getByRole('img');
    expect(canvas).toBeInTheDocument();
    expect(canvas.tagName).toBe('CANVAS');
  });

  it('has proper ARIA label when experiment is provided', () => {
    render(TimelineCanvas, { props: { experiment: mockExperiment } });

    const canvas = screen.getByRole('img');
    expect(canvas).toHaveAttribute('aria-label', 'Timeline visualization for Test Experiment');
  });

  it('has empty timeline ARIA label when no experiment', () => {
    render(TimelineCanvas, { props: { experiment: null } });

    const canvas = screen.getByRole('img');
    expect(canvas).toHaveAttribute('aria-label', 'Empty timeline');
  });

  it('is keyboard focusable', () => {
    render(TimelineCanvas);

    const canvas = screen.getByRole('img');
    expect(canvas).toHaveAttribute('tabindex', '0');
  });

  it('handles click events', async () => {
    const { component } = render(TimelineCanvas, { 
      props: { 
        experiment: mockExperiment,
        selectedElement: null 
      } 
    });

    const canvas = screen.getByRole('img');
    fireEvent.click(canvas, { clientX: 100, clientY: 100 });

    // The click should trigger hit testing
    await waitFor(() => {
      // Check that the renderer's hitTest method would be called
      expect(canvas).toBeInTheDocument();
    });
  });

  it('handles wheel events for zoom', () => {
    const { component } = render(TimelineCanvas, { 
      props: { 
        zoom: 1 
      } 
    });

    const canvas = screen.getByRole('img');
    const preventDefaultSpy = vi.fn();

    fireEvent.wheel(canvas, { 
      deltaY: -100,
      preventDefault: preventDefaultSpy
    });

    expect(preventDefaultSpy).toHaveBeenCalled();
  });

  it('handles mouse pan with shift key', () => {
    render(TimelineCanvas);

    const canvas = screen.getByRole('img');

    // Start panning with shift key
    fireEvent.mouseDown(canvas, { 
      button: 0, 
      shiftKey: true,
      clientX: 100,
      clientY: 100
    });

    // Move mouse
    fireEvent.mouseMove(window, { 
      clientX: 150,
      clientY: 150
    });

    // Stop panning
    fireEvent.mouseUp(window);

    // Canvas should have default cursor after mouseup
    expect(canvas.style.cursor).toBe('default');
  });

  it('handles middle mouse button pan', () => {
    render(TimelineCanvas);

    const canvas = screen.getByRole('img');

    // Start panning with middle button
    fireEvent.mouseDown(canvas, { 
      button: 1,
      clientX: 100,
      clientY: 100
    });

    expect(canvas.style.cursor).toBe('grabbing');

    // Stop panning
    fireEvent.mouseUp(window);

    expect(canvas.style.cursor).toBe('default');
  });

  it('updates when experiment prop changes', async () => {
    const { rerender } = render(TimelineCanvas, { 
      props: { 
        experiment: null 
      } 
    });

    expect(screen.getByRole('img')).toHaveAttribute('aria-label', 'Empty timeline');

    rerender({ props: { experiment: mockExperiment } });

    expect(screen.getByRole('img')).toHaveAttribute('aria-label', 'Timeline visualization for Test Experiment');
  });

  it('cleans up event listeners on unmount', () => {
    const removeEventListenerSpy = vi.spyOn(window, 'removeEventListener');

    const { unmount } = render(TimelineCanvas);

    unmount();

    expect(removeEventListenerSpy).toHaveBeenCalledWith('mousemove', expect.any(Function));
    expect(removeEventListenerSpy).toHaveBeenCalledWith('mouseup', expect.any(Function));
  });

  it('sets up resize observer', () => {
    const { container } = render(TimelineCanvas);

    const resizeObserver = MockResizeObserver.mock.instances[0];
    expect(resizeObserver.observe).toHaveBeenCalled();
  });

  it('disconnects resize observer on unmount', () => {
    const { unmount } = render(TimelineCanvas);

    const resizeObserver = MockResizeObserver.mock.instances[0];

    unmount();

    expect(resizeObserver.disconnect).toHaveBeenCalled();
  });
});

