import { render, screen, fireEvent } from '@testing-library/svelte';
import { describe, it, expect, vi } from 'vitest';
import Timeline from './Timeline.svelte';
import type { CompiledExperiment } from '$lib/types/experiment';

// Mock child components
vi.mock('./TimelineCanvas.svelte', () => ({
  default: {
    render: () => {
      const div = document.createElement('div');
      div.setAttribute('data-testid', 'timeline-canvas');
      return {
        container: div
      };
    }
  }
}));

vi.mock('./TimelineControls.svelte', () => ({
  default: {
    render: () => {
      const div = document.createElement('div');
      div.setAttribute('data-testid', 'timeline-controls');
      return {
        container: div
      };
    }
  }
}));

describe('Timeline', () => {
  const mockExperiment: CompiledExperiment = {
    id: 'exp-1',
    name: 'Test Experiment',
    duration: 10000,
    timelines: []
  };

  it('renders with title', () => {
    render(Timeline);

    expect(screen.getByText('Visual Timeline')).toBeInTheDocument();
  });

  it('renders timeline canvas and controls', () => {
    const { container } = render(Timeline);

    expect(container.querySelector('[data-testid="timeline-canvas"]')).toBeInTheDocument();
    expect(container.querySelector('[data-testid="timeline-controls"]')).toBeInTheDocument();
  });

  it('shows selection info when element is selected', () => {
    render(Timeline, { 
      props: { 
        selectedElement: 'element-123' 
      } 
    });

    expect(screen.getByText('Selected: element-123')).toBeInTheDocument();
  });

  it('does not show selection info when no element is selected', () => {
    render(Timeline, { 
      props: { 
        selectedElement: null 
      } 
    });

    expect(screen.queryByText(/Selected:/)).not.toBeInTheDocument();
  });

  it('passes experiment prop to canvas', () => {
    const { container } = render(Timeline, { 
      props: { 
        experiment: mockExperiment 
      } 
    });

    // Canvas should be rendered with experiment data
    expect(container.querySelector('[data-testid="timeline-canvas"]')).toBeInTheDocument();
  });

  it('updates selection when selectedElement changes', () => {
    const { rerender } = render(Timeline, { 
      props: { 
        selectedElement: null 
      } 
    });

    expect(screen.queryByText(/Selected:/)).not.toBeInTheDocument();

    rerender({ props: { selectedElement: 'new-element' } });

    expect(screen.getByText('Selected: new-element')).toBeInTheDocument();
  });

  it('has proper layout structure', () => {
    const { container } = render(Timeline);

    const timelineContainer = container.querySelector('.timeline-container');
    expect(timelineContainer).toBeInTheDocument();

    const header = container.querySelector('.timeline-header');
    expect(header).toBeInTheDocument();

    const viewport = container.querySelector('.timeline-viewport');
    expect(viewport).toBeInTheDocument();
  });
});

