import { render, screen, fireEvent } from '@testing-library/svelte';
import { describe, it, expect, vi } from 'vitest';
import TimelineControls from './TimelineControls.svelte';

describe('TimelineControls', () => {
  it('renders toolbar with proper ARIA attributes', () => {
    render(TimelineControls);

    const toolbar = screen.getByRole('toolbar', { name: 'Timeline controls' });
    expect(toolbar).toBeInTheDocument();
  });

  it('renders zoom buttons', () => {
    render(TimelineControls);

    expect(screen.getByLabelText('Zoom in timeline')).toBeInTheDocument();
    expect(screen.getByLabelText('Zoom out timeline')).toBeInTheDocument();
    expect(screen.getByLabelText('Fit timeline to view')).toBeInTheDocument();
    expect(screen.getByLabelText('Reset timeline view')).toBeInTheDocument();
  });

  it('displays current zoom level', () => {
    render(TimelineControls, { props: { zoom: 1 } });

    expect(screen.getByText('100%')).toBeInTheDocument();
  });

  it('updates zoom display when zoom prop changes', () => {
    const { rerender } = render(TimelineControls, { props: { zoom: 1 } });

    expect(screen.getByText('100%')).toBeInTheDocument();

    rerender({ props: { zoom: 2 } });
    expect(screen.getByText('200%')).toBeInTheDocument();

    rerender({ props: { zoom: 0.5 } });
    expect(screen.getByText('50%')).toBeInTheDocument();
  });

  it('emits zoom event when zoom in is clicked', () => {
    const { component } = render(TimelineControls, { props: { zoom: 1 } });

    const zoomSpy = vi.fn();
    component.$on('zoom', zoomSpy);

    const zoomInButton = screen.getByLabelText('Zoom in timeline');
    fireEvent.click(zoomInButton);

    expect(zoomSpy).toHaveBeenCalledWith(
      expect.objectContaining({
        detail: 1.2 // 1 * 1.2
      })
    );
  });

  it('emits zoom event when zoom out is clicked', () => {
    const { component } = render(TimelineControls, { props: { zoom: 1 } });

    const zoomSpy = vi.fn();
    component.$on('zoom', zoomSpy);

    const zoomOutButton = screen.getByLabelText('Zoom out timeline');
    fireEvent.click(zoomOutButton);

    expect(zoomSpy).toHaveBeenCalledWith(
      expect.objectContaining({
        detail: expect.closeTo(0.833, 3) // 1 / 1.2
      })
    );
  });

  it('disables zoom in button at max zoom', () => {
    render(TimelineControls, { props: { zoom: 5, maxZoom: 5 } });

    const zoomInButton = screen.getByLabelText('Zoom in timeline');
    expect(zoomInButton).toBeDisabled();
  });

  it('disables zoom out button at min zoom', () => {
    render(TimelineControls, { props: { zoom: 0.1, minZoom: 0.1 } });

    const zoomOutButton = screen.getByLabelText('Zoom out timeline');
    expect(zoomOutButton).toBeDisabled();
  });

  it('emits fit event when fit button is clicked', () => {
    const { component } = render(TimelineControls);

    const fitSpy = vi.fn();
    component.$on('fit', fitSpy);

    const fitButton = screen.getByLabelText('Fit timeline to view');
    fireEvent.click(fitButton);

    expect(fitSpy).toHaveBeenCalled();
  });

  it('emits reset event when reset button is clicked', () => {
    const { component } = render(TimelineControls, { props: { zoom: 2 } });

    const resetSpy = vi.fn();
    component.$on('reset', resetSpy);

    const resetButton = screen.getByLabelText('Reset timeline view');
    fireEvent.click(resetButton);

    expect(resetSpy).toHaveBeenCalled();
  });

  it('shows keyboard shortcuts in tooltips', () => {
    render(TimelineControls);

    const zoomInButton = screen.getByLabelText('Zoom in timeline');
    expect(zoomInButton).toHaveAttribute('title', 'Zoom in (Ctrl+Plus)');

    const zoomOutButton = screen.getByLabelText('Zoom out timeline');
    expect(zoomOutButton).toHaveAttribute('title', 'Zoom out (Ctrl+Minus)');

    const fitButton = screen.getByLabelText('Fit timeline to view');
    expect(fitButton).toHaveAttribute('title', 'Fit to view (Ctrl+0)');
  });

  it('shows pan hint', () => {
    render(TimelineControls);

    expect(screen.getByText('Shift+drag to pan')).toBeInTheDocument();
  });

  it('respects zoom limits', () => {
    const { component } = render(TimelineControls, { 
      props: { 
        zoom: 4.9, 
        maxZoom: 5 
      } 
    });

    const zoomSpy = vi.fn();
    component.$on('zoom', zoomSpy);

    const zoomInButton = screen.getByLabelText('Zoom in timeline');
    fireEvent.click(zoomInButton);

    // Should cap at maxZoom
    expect(zoomSpy).toHaveBeenCalledWith(
      expect.objectContaining({
        detail: 5
      })
    );
  });
});

