import { render, screen } from '@testing-library/svelte';
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import MonacoEditor from './MonacoEditor.svelte';

// Mock monaco-editor
const mockEditor = {
  getValue: vi.fn(() => ''),
  setValue: vi.fn(),
  updateOptions: vi.fn(),
  onDidChangeModelContent: vi.fn(),
  layout: vi.fn(),
  dispose: vi.fn(),
  getAction: vi.fn(() => ({ run: vi.fn() })),
  trigger: vi.fn()
};

vi.mock('monaco-editor', () => ({
  editor: {
    create: vi.fn(() => mockEditor),
    defineTheme: vi.fn(),
    setTheme: vi.fn()
  },
  languages: {
    typescript: {
      typescriptDefaults: {
        setCompilerOptions: vi.fn(),
        setDiagnosticsOptions: vi.fn()
      },
      ScriptTarget: { ES2020: 'ES2020' },
      ModuleResolutionKind: { NodeJs: 'NodeJs' },
      ModuleKind: { ESNext: 'ESNext' },
      JsxEmit: { React: 'React' }
    }
  }
}));

// Mock ResizeObserver
class MockResizeObserver {
  observe = vi.fn();
  unobserve = vi.fn();
  disconnect = vi.fn();
}

global.ResizeObserver = MockResizeObserver as any;

// Mock language definition
vi.mock('./forgescript-language', () => ({
  defineForgeScriptLanguage: vi.fn()
}));

describe('MonacoEditor', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('renders container with proper ARIA attributes', () => {
    render(MonacoEditor);

    const container = screen.getByRole('textbox', { name: 'Code editor' });
    expect(container).toBeInTheDocument();
    expect(container).toHaveAttribute('aria-multiline', 'true');
  });

  it('initializes editor with default props', () => {
    const monaco = require('monaco-editor');
    render(MonacoEditor);

    expect(monaco.editor.create).toHaveBeenCalledWith(
      expect.any(HTMLElement),
      expect.objectContaining({
        value: '',
        language: 'typescript',
        theme: 'psyforge-light',
        readOnly: false,
        minimap: { enabled: false },
        lineNumbers: 'on'
      })
    );
  });

  it('initializes with custom value', () => {
    const monaco = require('monaco-editor');
    const code = 'const x = 42;';

    render(MonacoEditor, { props: { value: code } });

    expect(monaco.editor.create).toHaveBeenCalledWith(
      expect.any(HTMLElement),
      expect.objectContaining({
        value: code
      })
    );
  });

  it('updates value when prop changes', () => {
    const { rerender } = render(MonacoEditor, { props: { value: 'initial' } });

    const newValue = 'updated code';
    rerender({ props: { value: newValue } });

    expect(mockEditor.setValue).toHaveBeenCalledWith(newValue);
  });

  it('changes theme when prop updates', () => {
    const monaco = require('monaco-editor');
    const { rerender } = render(MonacoEditor, { props: { theme: 'psyforge-light' } });

    rerender({ props: { theme: 'psyforge-dark' } });

    expect(monaco.editor.setTheme).toHaveBeenCalledWith('psyforge-dark');
  });

  it('updates editor options when props change', () => {
    const { rerender } = render(MonacoEditor, { 
      props: { 
        readOnly: false,
        minimap: false,
        lineNumbers: 'on'
      } 
    });

    rerender({ 
      props: { 
        readOnly: true,
        minimap: true,
        lineNumbers: 'off'
      } 
    });

    expect(mockEditor.updateOptions).toHaveBeenCalledWith({
      readOnly: true,
      minimap: { enabled: true },
      lineNumbers: 'off'
    });
  });

  it('sets up resize observer', () => {
    render(MonacoEditor);

    const resizeObserver = MockResizeObserver.mock.instances[0];
    expect(resizeObserver.observe).toHaveBeenCalledWith(expect.any(HTMLElement));
  });

  it('handles editor content changes', () => {
    render(MonacoEditor);

    expect(mockEditor.onDidChangeModelContent).toHaveBeenCalled();
  });

  it('exposes format method', () => {
    const { component } = render(MonacoEditor);

    component.format();

    expect(mockEditor.getAction).toHaveBeenCalledWith('editor.action.formatDocument');
  });

  it('exposes undo method', () => {
    const { component } = render(MonacoEditor);

    component.undo();

    expect(mockEditor.trigger).toHaveBeenCalledWith('keyboard', 'undo', null);
  });

  it('exposes redo method', () => {
    const { component } = render(MonacoEditor);

    component.redo();

    expect(mockEditor.trigger).toHaveBeenCalledWith('keyboard', 'redo', null);
  });

  it('exposes find method', () => {
    const { component } = render(MonacoEditor);

    component.find();

    expect(mockEditor.getAction).toHaveBeenCalledWith('actions.find');
  });

  it('exposes replace method', () => {
    const { component } = render(MonacoEditor);

    component.replace();

    expect(mockEditor.getAction).toHaveBeenCalledWith('editor.action.startFindReplaceAction');
  });

  it('disposes editor on unmount', () => {
    const { unmount } = render(MonacoEditor);

    unmount();

    expect(mockEditor.dispose).toHaveBeenCalled();
  });

  it('disconnects resize observer on unmount', () => {
    const { unmount } = render(MonacoEditor);

    const resizeObserver = MockResizeObserver.mock.instances[0];

    unmount();

    expect(resizeObserver.disconnect).toHaveBeenCalled();
  });

  it('defines custom themes on mount', () => {
    const monaco = require('monaco-editor');
    render(MonacoEditor);

    expect(monaco.editor.defineTheme).toHaveBeenCalledWith('psyforge-light', expect.any(Object));
    expect(monaco.editor.defineTheme).toHaveBeenCalledWith('psyforge-dark', expect.any(Object));
  });

  it('configures TypeScript on mount', () => {
    const monaco = require('monaco-editor');
    render(MonacoEditor);

    expect(monaco.languages.typescript.typescriptDefaults.setCompilerOptions).toHaveBeenCalled();
    expect(monaco.languages.typescript.typescriptDefaults.setDiagnosticsOptions).toHaveBeenCalled();
  });
});

