import { render, screen, fireEvent } from '@testing-library/svelte';
import { describe, it, expect, vi, beforeEach } from 'vitest';
import CodeEditor from './CodeEditor.svelte';

// Mock MonacoEditor
vi.mock('./MonacoEditor.svelte', () => ({
  default: {
    render: () => {
      const div = document.createElement('div');
      div.setAttribute('data-testid', 'monaco-editor');
      return {
        container: div,
        format: vi.fn(),
        undo: vi.fn(),
        redo: vi.fn(),
        find: vi.fn(),
        replace: vi.fn()
      };
    }
  }
}));

describe('CodeEditor', () => {
  beforeEach(() => {
    document.documentElement.setAttribute('data-theme', 'light');
  });

  it('renders with toolbar by default', () => {
    render(CodeEditor);

    expect(screen.getByLabelText('Save code')).toBeInTheDocument();
    expect(screen.getByLabelText('Run experiment')).toBeInTheDocument();
  });

  it('hides toolbar when showToolbar is false', () => {
    render(CodeEditor, { props: { showToolbar: false } });

    expect(screen.queryByLabelText('Save code')).not.toBeInTheDocument();
    expect(screen.queryByLabelText('Run experiment')).not.toBeInTheDocument();
  });

  it('renders all toolbar buttons', () => {
    render(CodeEditor);

    expect(screen.getByLabelText('Save code')).toBeInTheDocument();
    expect(screen.getByLabelText('Run experiment')).toBeInTheDocument();
    expect(screen.getByLabelText('Undo')).toBeInTheDocument();
    expect(screen.getByLabelText('Redo')).toBeInTheDocument();
    expect(screen.getByLabelText('Find')).toBeInTheDocument();
    expect(screen.getByLabelText('Replace')).toBeInTheDocument();
    expect(screen.getByLabelText('Format code')).toBeInTheDocument();
  });

  it('shows keyboard shortcuts in tooltips', () => {
    render(CodeEditor);

    expect(screen.getByLabelText('Save code')).toHaveAttribute('title', 'Save (Ctrl+S)');
    expect(screen.getByLabelText('Run experiment')).toHaveAttribute('title', 'Run (Ctrl+Enter)');
    expect(screen.getByLabelText('Undo')).toHaveAttribute('title', 'Undo (Ctrl+Z)');
    expect(screen.getByLabelText('Format code')).toHaveAttribute('title', 'Format (Shift+Alt+F)');
  });

  it('disables save button when not dirty or readonly', () => {
    const { rerender } = render(CodeEditor, { 
      props: { 
        isDirty: false, 
        readOnly: false 
      } 
    });

    expect(screen.getByLabelText('Save code')).toBeDisabled();

    rerender({ props: { isDirty: true, readOnly: false } });
    expect(screen.getByLabelText('Save code')).not.toBeDisabled();

    rerender({ props: { isDirty: true, readOnly: true } });
    expect(screen.getByLabelText('Save code')).toBeDisabled();
  });

  it('disables run button when syntax is invalid or readonly', () => {
    const { rerender } = render(CodeEditor, { 
      props: { 
        syntaxValid: false, 
        readOnly: false 
      } 
    });

    expect(screen.getByLabelText('Run experiment')).toBeDisabled();

    rerender({ props: { syntaxValid: true, readOnly: false } });
    expect(screen.getByLabelText('Run experiment')).not.toBeDisabled();

    rerender({ props: { syntaxValid: true, readOnly: true } });
    expect(screen.getByLabelText('Run experiment')).toBeDisabled();
  });

  it('shows modified status when dirty', () => {
    const { rerender } = render(CodeEditor, { props: { isDirty: false } });

    expect(screen.queryByText('Modified')).not.toBeInTheDocument();

    rerender({ props: { isDirty: true } });
    expect(screen.getByText('Modified')).toBeInTheDocument();
  });

  it('shows syntax validation status', () => {
    const { rerender } = render(CodeEditor, { props: { syntaxValid: true } });

    expect(screen.getByText('Valid')).toBeInTheDocument();
    expect(screen.queryByText('Syntax Error')).not.toBeInTheDocument();

    rerender({ props: { syntaxValid: false } });
    expect(screen.queryByText('Valid')).not.toBeInTheDocument();
    expect(screen.getByText('Syntax Error')).toBeInTheDocument();
  });

  it('emits save event on save button click', () => {
    const { component } = render(CodeEditor, { 
      props: { 
        value: 'test code',
        isDirty: true 
      } 
    });

    const saveSpy = vi.fn();
    component.$on('save', saveSpy);

    fireEvent.click(screen.getByLabelText('Save code'));

    expect(saveSpy).toHaveBeenCalledWith(
      expect.objectContaining({
        detail: 'test code'
      })
    );
  });

  it('emits run event on run button click', () => {
    const { component } = render(CodeEditor, { 
      props: { 
        value: 'test code',
        syntaxValid: true 
      } 
    });

    const runSpy = vi.fn();
    component.$on('run', runSpy);

    fireEvent.click(screen.getByLabelText('Run experiment'));

    expect(runSpy).toHaveBeenCalledWith(
      expect.objectContaining({
        detail: 'test code'
      })
    );
  });

  it('handles keyboard shortcuts', () => {
    const { component } = render(CodeEditor, { 
      props: { 
        value: 'test code',
        isDirty: true,
        syntaxValid: true
      } 
    });

    const saveSpy = vi.fn();
    const runSpy = vi.fn();
    component.$on('save', saveSpy);
    component.$on('run', runSpy);

    // Test Ctrl+S
    fireEvent.keyDown(window, { key: 's', ctrlKey: true });
    expect(saveSpy).toHaveBeenCalled();

    // Test Ctrl+Enter
    fireEvent.keyDown(window, { key: 'Enter', ctrlKey: true });
    expect(runSpy).toHaveBeenCalled();
  });

  it('disables editing buttons when readonly', () => {
    render(CodeEditor, { props: { readOnly: true } });

    expect(screen.getByLabelText('Undo')).toBeDisabled();
    expect(screen.getByLabelText('Redo')).toBeDisabled();
    expect(screen.getByLabelText('Replace')).toBeDisabled();
    expect(screen.getByLabelText('Format code')).toBeDisabled();

    // Find should still be enabled
    expect(screen.getByLabelText('Find')).not.toBeDisabled();
  });

  it('renders monaco editor component', () => {
    const { container } = render(CodeEditor);

    expect(container.querySelector('[data-testid="monaco-editor"]')).toBeInTheDocument();
  });
});

