import { describe, it, expect, beforeEach } from 'vitest';
import { get } from 'svelte/store';
import { toasts, type Toast } from './toasts';

describe('toasts store', () => {
  beforeEach(() => {
    // Clear toasts before each test
    toasts.clear();
  });

  it('initializes with empty array', () => {
    expect(get(toasts)).toEqual([]);
  });

  it('adds toast with auto-generated id', () => {
    const id = toasts.add({
      type: 'info',
      message: 'Test message'
    });

    expect(id).toMatch(/^toast-\d+$/);

    const allToasts = get(toasts);
    expect(allToasts).toHaveLength(1);
    expect(allToasts[0]).toEqual({
      id,
      type: 'info',
      message: 'Test message',
      duration: 5000,
      closable: true
    });
  });

  it('adds multiple toasts with unique ids', () => {
    const id1 = toasts.add({ type: 'info', message: 'First' });
    const id2 = toasts.add({ type: 'info', message: 'Second' });

    expect(id1).not.toBe(id2);

    const allToasts = get(toasts);
    expect(allToasts).toHaveLength(2);
    expect(allToasts[0].id).toBe(id1);
    expect(allToasts[1].id).toBe(id2);
  });

  it('removes toast by id', () => {
    const id1 = toasts.add({ type: 'info', message: 'First' });
    const id2 = toasts.add({ type: 'info', message: 'Second' });

    toasts.remove(id1);

    const allToasts = get(toasts);
    expect(allToasts).toHaveLength(1);
    expect(allToasts[0].id).toBe(id2);
  });

  it('clear removes all toasts', () => {
    toasts.add({ type: 'info', message: 'First' });
    toasts.add({ type: 'info', message: 'Second' });
    toasts.add({ type: 'info', message: 'Third' });

    expect(get(toasts)).toHaveLength(3);

    toasts.clear();

    expect(get(toasts)).toHaveLength(0);
  });

  it('success method creates success toast', () => {
    const id = toasts.success('Success message');

    const allToasts = get(toasts);
    expect(allToasts[0]).toMatchObject({
      id,
      type: 'success',
      message: 'Success message'
    });
  });

  it('error method creates error toast', () => {
    const id = toasts.error('Error message');

    const allToasts = get(toasts);
    expect(allToasts[0]).toMatchObject({
      id,
      type: 'error',
      message: 'Error message'
    });
  });

  it('warning method creates warning toast', () => {
    const id = toasts.warning('Warning message');

    const allToasts = get(toasts);
    expect(allToasts[0]).toMatchObject({
      id,
      type: 'warning',
      message: 'Warning message'
    });
  });

  it('info method creates info toast', () => {
    const id = toasts.info('Info message');

    const allToasts = get(toasts);
    expect(allToasts[0]).toMatchObject({
      id,
      type: 'info',
      message: 'Info message'
    });
  });

  it('allows custom options in convenience methods', () => {
    toasts.success('Success', { duration: 10000, closable: false });

    const allToasts = get(toasts);
    expect(allToasts[0]).toMatchObject({
      type: 'success',
      message: 'Success',
      duration: 10000,
      closable: false
    });
  });

  it('uses default values for duration and closable', () => {
    toasts.add({ type: 'info', message: 'Test' });

    const allToasts = get(toasts);
    expect(allToasts[0].duration).toBe(5000);
    expect(allToasts[0].closable).toBe(true);
  });

  it('can override default values', () => {
    toasts.add({ 
      type: 'info', 
      message: 'Test',
      duration: 0,
      closable: false
    });

    const allToasts = get(toasts);
    expect(allToasts[0].duration).toBe(0);
    expect(allToasts[0].closable).toBe(false);
  });

  it('maintains toast order', () => {
    toasts.success('First');
    toasts.error('Second');
    toasts.warning('Third');
    toasts.info('Fourth');

    const allToasts = get(toasts);
    expect(allToasts[0].message).toBe('First');
    expect(allToasts[1].message).toBe('Second');
    expect(allToasts[2].message).toBe('Third');
    expect(allToasts[3].message).toBe('Fourth');
  });
});

