// Theme initialization utility
// This will be included via SvelteKit's app.html hooks system

export function initializeTheme() {
  const saved = localStorage.getItem('psyforge-settings');
  if (saved) {
    try {
      const settings = JSON.parse(saved);
      document.documentElement.className = settings.theme || 'light';
      if (settings.accessibility?.fontSize) {
        document.documentElement.setAttribute('data-font-size', settings.accessibility.fontSize);
      }
    } catch (e) {
      // Fallback to light theme if settings are corrupted
      document.documentElement.className = 'light';
    }
  } else {
    // Default to light theme
    document.documentElement.className = 'light';
  }
}

