import type { CompiledExperiment, TimelineNode, Trial, Stimulus } from '$lib/types/experiment';

interface RenderNode {
  id: string;
  type: 'experiment' | 'timeline' | 'trial' | 'stimulus';
  name: string;
  x: number;
  y: number;
  width: number;
  height: number;
  startTime: number;
  duration: number;
  children?: RenderNode[];
  data: any;
}

interface TimelineColors {
  experiment: string;
  timeline: string;
  trial: string;
  stimulus: string;
  selected: string;
  text: string;
  grid: string;
  ruler: string;
}

const DEFAULT_COLORS: TimelineColors = {
  experiment: '#3b82f6',
  timeline: '#8b5cf6',
  trial: '#10b981',
  stimulus: '#f59e0b',
  selected: '#dc2626',
  text: '#1f2937',
  grid: '#e5e7eb',
  ruler: '#6b7280'
};

export function createTimelineRenderer(ctx: CanvasRenderingContext2D) {
  let experiment: CompiledExperiment | null = null;
  let selectedElement: string | null = null;
  let zoom = 1;
  let panX = 0;
  let panY = 0;
  let width = 0;
  let height = 0;
  let renderTree: RenderNode | null = null;

  const pixelsPerMs = 0.1; // Base scale: 1 pixel = 10ms
  const rowHeight = 60;
  const rowGap = 10;
  const nodeGap = 20;
  const paddingX = 50;
  const paddingY = 50;

  function setDimensions(w: number, h: number) {
    width = w;
    height = h;
  }

  function setExperiment(exp: CompiledExperiment | null) {
    experiment = exp;
    if (exp) {
      renderTree = buildRenderTree(exp);
    } else {
      renderTree = null;
    }
  }

  function setSelectedElement(id: string | null) {
    selectedElement = id;
  }

  function setZoom(z: number) {
    zoom = z;
  }

  function setPan(x: number, y: number) {
    panX = x;
    panY = y;
  }

  function buildRenderTree(exp: CompiledExperiment): RenderNode {
    const root: RenderNode = {
      id: exp.id,
      type: 'experiment',
      name: exp.name,
      x: 0,
      y: 0,
      width: 0,
      height: 0,
      startTime: 0,
      duration: exp.duration || 0,
      children: [],
      data: exp
    };

    let currentY = rowHeight + rowGap;

    // Build timeline nodes
    exp.timelines?.forEach((timeline, tIndex) => {
      const timelineNode: RenderNode = {
        id: `timeline-${tIndex}`,
        type: 'timeline',
        name: timeline.name || `Timeline ${tIndex + 1}`,
        x: 0,
        y: currentY,
        width: 0,
        height: rowHeight,
        startTime: timeline.startTime || 0,
        duration: timeline.duration || 0,
        children: [],
        data: timeline
      };

      currentY += rowHeight + rowGap;

      // Build trial nodes
      timeline.trials?.forEach((trial, trIndex) => {
        const trialNode: RenderNode = {
          id: `trial-${tIndex}-${trIndex}`,
          type: 'trial',
          name: trial.name || `Trial ${trIndex + 1}`,
          x: 0,
          y: currentY,
          width: 0,
          height: rowHeight,
          startTime: trial.startTime || 0,
          duration: trial.duration || 0,
          children: [],
          data: trial
        };

        currentY += rowHeight + rowGap;

        // Build stimulus nodes
        trial.stimuli?.forEach((stimulus, sIndex) => {
          const stimulusNode: RenderNode = {
            id: `stimulus-${tIndex}-${trIndex}-${sIndex}`,
            type: 'stimulus',
            name: stimulus.name || `Stimulus ${sIndex + 1}`,
            x: 0,
            y: currentY,
            width: 0,
            height: rowHeight * 0.8,
            startTime: stimulus.startTime || 0,
            duration: stimulus.duration || 0,
            data: stimulus
          };

          // Calculate positions
          stimulusNode.x = paddingX + (stimulusNode.startTime * pixelsPerMs * zoom);
          stimulusNode.width = Math.max(50, stimulusNode.duration * pixelsPerMs * zoom);

          trialNode.children?.push(stimulusNode);
        });

        // Calculate trial dimensions
        trialNode.x = paddingX + (trialNode.startTime * pixelsPerMs * zoom);
        trialNode.width = Math.max(100, trialNode.duration * pixelsPerMs * zoom);

        timelineNode.children?.push(trialNode);

        if (trial.stimuli && trial.stimuli.length > 0) {
          currentY += (rowHeight * 0.8 + rowGap / 2) * trial.stimuli.length;
        }
      });

      // Calculate timeline dimensions
      timelineNode.x = paddingX;
      timelineNode.width = Math.max(200, timelineNode.duration * pixelsPerMs * zoom);

      root.children?.push(timelineNode);
    });

    // Calculate experiment dimensions
    root.width = Math.max(300, root.duration * pixelsPerMs * zoom);
    root.height = currentY + paddingY;

    return root;
  }

  function render() {
    if (!ctx || !width || !height) return;

    // Clear canvas
    ctx.clearRect(0, 0, width * window.devicePixelRatio, height * window.devicePixelRatio);

    // Save context state
    ctx.save();

    // Apply device pixel ratio
    ctx.scale(window.devicePixelRatio, window.devicePixelRatio);

    // Apply pan
    ctx.translate(panX, panY);

    // Draw background
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(-panX, -panY, width, height);

    // Draw grid
    drawGrid();

    // Draw time ruler
    drawTimeRuler();

    // Draw timeline
    if (renderTree) {
      drawNode(renderTree);
    }

    // Restore context state
    ctx.restore();
  }

  function drawGrid() {
    ctx.strokeStyle = DEFAULT_COLORS.grid;
    ctx.lineWidth = 1;
    ctx.setLineDash([5, 5]);

    // Vertical grid lines (time markers)
    const msPerLine = 1000; // 1 second intervals
    const totalMs = 60000; // Show up to 1 minute

    for (let ms = 0; ms <= totalMs; ms += msPerLine) {
      const x = paddingX + (ms * pixelsPerMs * zoom);
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, height);
      ctx.stroke();
    }

    ctx.setLineDash([]);
  }

  function drawTimeRuler() {
    ctx.fillStyle = DEFAULT_COLORS.ruler;
    ctx.font = '12px system-ui';

    // Draw time labels
    const msPerLabel = 1000; // 1 second intervals
    const totalMs = 60000; // Show up to 1 minute

    for (let ms = 0; ms <= totalMs; ms += msPerLabel) {
      const x = paddingX + (ms * pixelsPerMs * zoom);
      const seconds = ms / 1000;

      ctx.fillText(`${seconds}s`, x - 10, 30);
    }
  }

  function drawNode(node: RenderNode) {
    // Set color based on type and selection
    const isSelected = node.id === selectedElement;
    ctx.fillStyle = isSelected ? DEFAULT_COLORS.selected : DEFAULT_COLORS[node.type];

    // Draw rectangle
    ctx.fillRect(node.x, node.y, node.width, node.height);

    // Draw border
    ctx.strokeStyle = isSelected ? DEFAULT_COLORS.selected : '#00000020';
    ctx.lineWidth = isSelected ? 2 : 1;
    ctx.strokeRect(node.x, node.y, node.width, node.height);

    // Draw label
    ctx.fillStyle = DEFAULT_COLORS.text;
    ctx.font = `${node.type === 'stimulus' ? 12 : 14}px system-ui`;
    ctx.textAlign = 'left';
    ctx.textBaseline = 'middle';

    // Clip text to node bounds
    ctx.save();
    ctx.beginPath();
    ctx.rect(node.x, node.y, node.width, node.height);
    ctx.clip();

    ctx.fillText(node.name, node.x + 10, node.y + node.height / 2);

    ctx.restore();

    // Draw children
    if (node.children) {
      node.children.forEach(child => drawNode(child));
    }
  }

  function hitTest(x: number, y: number): RenderNode | null {
    if (!renderTree) return null;

    // Apply inverse transforms
    const testX = x - panX;
    const testY = y - panY;

    return hitTestNode(renderTree, testX, testY);
  }

  function hitTestNode(node: RenderNode, x: number, y: number): RenderNode | null {
    // Test children first (they're drawn on top)
    if (node.children) {
      for (const child of node.children.reverse()) {
        const hit = hitTestNode(child, x, y);
        if (hit) return hit;
      }
    }

    // Test this node
    if (x >= node.x && x <= node.x + node.width &&
        y >= node.y && y <= node.y + node.height) {
      return node;
    }

    return null;
  }

  return {
    setDimensions,
